#include<bits/stdc++.h>
using namespace std;
#define ll long long
ll n,a,b,c;
int main(){
	ios::sync_with_stdio(false);cin.tie(0);cout.tie(0);
	cin>>n;
	while(n){
		if(n==1) {cout<<1;exit(0);}
		if(n==2) {cout<<2;exit(0);};
		a=1,b=2,c=3;
		while(c<n) a=b,b=c,c=a+b;
		if(c==n){
            cout<<c;
            exit(0);
        }
		n-=b;
	}
	return 0;
}
